import { useState, useEffect } from "react";


const LOGO_SRC = "data:image/png;base64,";

const memStore = {};
const storage = {
  get: (k) => { const v = memStore[k]; return v ? { value: v } : null; },
  set: (k, v) => { memStore[k] = v; return true; },
};

const TODAY = new Date().toISOString().split("T")[0];
const IS_SUNDAY = new Date().getDay() === 0;
const PLAN_MONTHS = { 1: 1, 2: 2, 3: 3 };
const PLAN_LABELS = { 1: "شهر", 2: "شهرين", 3: "٣ أشهر" };

const DEMO_CLIENTS = [
  { name: "Sarah M.",  code: "1234", plan: 1, startDate: "2026-02-16" },
  { name: "Amal K.",   code: "5678", plan: 2, startDate: "2026-01-20" },
  { name: "Noor H.",   code: "9012", plan: 3, startDate: "2026-01-01" },
  { name: "Fatima R.", code: "3456", plan: 1, startDate: "2026-03-01" },
];

function getSubInfo(sub) {
  if (!sub) return null;
  const start = new Date(sub.startDate);
  const now = new Date();
  const totalDays = PLAN_MONTHS[sub.plan] * 30;
  const elapsed = Math.floor((now - start) / 86400000);
  const weeksDone = Math.floor(elapsed / 7);
  const weeksTotal = Math.floor(totalDays / 7);
  const weeksLeft = Math.max(0, weeksTotal - weeksDone);
  const followupsTotal = PLAN_MONTHS[sub.plan] * 4;
  const followupsDone = Math.min(weeksDone, followupsTotal);
  const followupsLeft = Math.max(0, followupsTotal - followupsDone);
  const isWeekMilestone = elapsed > 0 && elapsed % 7 === 0;
  const remaining = Math.max(0, totalDays - elapsed);
  return { weeksDone, weeksLeft, weeksTotal, followupsDone, followupsLeft, followupsTotal, isWeekMilestone, remaining, plan: sub.plan, totalDays };
}

const MEALS = [
  { key: "breakfast", label: "الفطار",  icon: "🥣", color: "#D4829A" },
  { key: "lunch",     label: "الغدا",   icon: "🥗", color: "#9B72AA" },
  { key: "dinner",    label: "العشا",   icon: "🍽️", color: "#7B8FCC" },
  { key: "snack",     label: "السناك",  icon: "🍎", color: "#C9607A" },
];

const defaultLog = {
  weight: "", waist: "", hips: "", arm: "",
  water: "", sleep: "", stress: 5,
  period: null,
  meals: "", salad: null, fastFood: null,
  coffee: "", supplements: null, followedPlan: null,
  exercise: null, exerciseMin: "", binge: null, mood: "", note: "",
  photos: { breakfast: null, lunch: null, dinner: null, snack: null },
};

const C = {
  bg: "#FDF8F5", card: "#FFFFFF", border: "#EDD9E5", borderLight: "#F5EBF0",
  pink: "#C2607A", rose: "#D4829A", mauve: "#9B72AA", lavender: "#B8A0CC",
  blush: "#F2D5DF", peach: "#F7E8E0",
  text: "#2D1F28", sub: "#8A6070", muted: "#BFA0AD", red: "#C9607A",
  white: "#FFFFFF", shadow: "rgba(194, 96, 122, 0.12)",
  green: "#6BAE8A",
};

const WEEK_MESSAGES = [
  { title: "أنهيتِ أسبوعك الأول! 🌸", body: "خطوة رائعة — الاستمرارية هي السر. استعدي للأسبوع الجاي!" },
  { title: "أسبوعان خلصوا! 💪",        body: "نصف الشهر راح وأنتِ ماشية بثبات. فخورة بيكِ!" },
  { title: "ثلاثة أسابيع! ✨",          body: "جسمك بدأ يتكيف — استمري على نفس الطاقة!" },
  { title: "أنهيتِ الشهر الأول! 🎉",   body: "إنجاز حقيقي! راجعي تقدمك مع دكتورتك." },
];

// Google Font import
const FONT_STYLE = `
  @import url('https://fonts.googleapis.com/css2?family=Tajawal:wght@400;500;700;800;900&display=swap');
  * { font-family: 'Tajawal', Georgia, serif; }
  @keyframes shake {
    0%,100%{transform:translateX(0)}
    20%{transform:translateX(-8px)} 40%{transform:translateX(8px)}
    60%{transform:translateX(-6px)} 80%{transform:translateX(6px)}
  }
  .code-dot { width:15px; height:15px; border-radius:50%; border:2.5px solid #EDD9E5; transition:all 0.2s; }
  .code-dot.filled { background:#C2607A; border-color:#C2607A; box-shadow:0 0 8px #C2607A60; }
  .numpad-btn {
    background:#FDF8F5; border:1.5px solid #EDD9E5; border-radius:16px;
    width:72px; height:60px; font-size:22px; font-family:'Tajawal',serif;
    color:#2D1F28; cursor:pointer; transition:all 0.15s; font-weight:700;
  }
  .numpad-btn:active { background:#F2D5DF; border-color:#C2607A; transform:scale(0.93); }
  .numpad-btn.del { font-size:17px; color:#BFA0AD; }
`;

export default function ClientDailyLog() {
  const [loggedInClient, setLoggedInClient] = useState(null);
  const [codeInput, setCodeInput] = useState("");
  const [codeError, setCodeError] = useState(false);
  const [shaking, setShaking] = useState(false);
  const [log, setLog] = useState(defaultLog);
  const [submitted, setSubmitted] = useState(false);
  const [loading, setLoading] = useState(false);
  const [alreadyLogged, setAlreadyLogged] = useState(false);
  const [step, setStep] = useState(0);
  const [dismissedMilestone, setDismissedMilestone] = useState(false);

  const clients = (() => {
    try { const r = storage.get("__clients__"); return r ? JSON.parse(r.value) : DEMO_CLIENTS; }
    catch { return DEMO_CLIENTS; }
  })();

  useEffect(() => {
    try {
      const saved = storage.get("__session__");
      if (saved) { const cl = clients.find(c => c.name === saved.value); if (cl) setLoggedInClient(cl); }
    } catch {}
  }, []);

  useEffect(() => { if (loggedInClient) checkExisting(); }, [loggedInClient]);

  function handleLogin() {
    const found = clients.find(c => c.code === codeInput.trim());
    if (found) { storage.set("__session__", found.name); setLoggedInClient(found); setCodeError(false); }
    else { setCodeError(true); setShaking(true); setTimeout(() => setShaking(false), 600); setCodeInput(""); }
  }

  function handleLogout() {
    storage.set("__session__", ""); setLoggedInClient(null);
    setLog(defaultLog); setSubmitted(false); setStep(0); setCodeInput("");
  }

  function checkExisting() {
    const key = `log:${loggedInClient?.name}:${TODAY}`;
    try {
      const res = storage.get(key);
      if (res?.value) { setAlreadyLogged(true); setLog(JSON.parse(res.value)); }
      else { setAlreadyLogged(false); setLog(defaultLog); setSubmitted(false); setStep(0); }
    } catch { setAlreadyLogged(false); }
  }

  function handleSubmit() {
    setLoading(true);
    const key = `log:${loggedInClient.name}:${TODAY}`;
    try {
      storage.set(key, JSON.stringify({ ...log, date: TODAY, client: loggedInClient.name, submittedAt: new Date().toISOString() }));
      let ex = []; try { const r = storage.get(`loglist:${loggedInClient.name}`); if (r) ex = JSON.parse(r.value); } catch {}
      storage.set(`loglist:${loggedInClient.name}`, JSON.stringify([TODAY, ...ex.filter(d => d !== TODAY)].slice(0, 90)));
      setSubmitted(true);
    } catch { alert("حصل خطأ، حاولي تاني."); }
    setLoading(false);
  }

  const set = (k, v) => setLog(p => ({ ...p, [k]: v }));
  const setPhoto = (meal, data) => setLog(p => ({ ...p, photos: { ...p.photos, [meal]: data } }));
  const photoCount = Object.values(log.photos || {}).filter(Boolean).length;

  // ── LOGIN ──
  if (!loggedInClient) {
    return (
      <div style={{ background: C.bg, minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", padding: 24 }}>
        <style>{FONT_STYLE}</style>
        <div style={{ width: "100%", maxWidth: 360, textAlign: "center" }}>

          {/* Logo placeholder + title */}
          <div style={{ marginBottom: 32 }}>
            <div style={{ width: 150, height: 150, margin: "0 auto 14px", display: "flex", alignItems: "center", justifyContent: "center" }}>
              <img src={LOGO_SRC} alt="Nutri Me" style={{ width: "100%", height: "100%", objectFit: "contain", filter: "drop-shadow(0 4px 12px rgba(155,114,170,0.20))" }} />
            </div>
            <div style={{ fontSize: 13, fontWeight: 700, color: C.mauve, letterSpacing: 1.5, marginBottom: 10, display: "flex", alignItems: "center", justifyContent: "center", gap: 6 }}>
              <span>Your online nutrition clinic</span>
              <span style={{ fontSize: 16, animation: "heartbeat 1.2s ease-in-out infinite" }}>🩷</span>
            </div>
            <style>{`@keyframes heartbeat { 0%,100%{transform:scale(1)} 30%{transform:scale(1.35)} 60%{transform:scale(1.1)} }`}</style>
            <h1 style={{ fontSize: 32, fontWeight: 900, color: C.pink, margin: 0, letterSpacing: 1 }}>أهلاً بكِ</h1>
            <p style={{ fontSize: 14, color: C.muted, marginTop: 8, lineHeight: 1.8, fontWeight: 500 }}>
              أدخلي الكود السري الخاص بكِ<br />للدخول على تسجيلك اليومي
            </p>
          </div>

          {/* PIN card */}
          <div style={{ background: C.white, border: `1.5px solid ${shaking ? C.red : codeError ? C.red : C.border}`, borderRadius: 24, padding: "28px 22px", boxShadow: `0 8px 32px ${C.shadow}`, animation: shaking ? "shake 0.5s ease" : "none" }}>

            <div style={{ display: "flex", gap: 14, justifyContent: "center", marginBottom: 22 }}>
              {[0,1,2,3].map(i => <div key={i} className={`code-dot${codeInput.length > i ? " filled" : ""}`} />)}
            </div>

            {codeError && (
              <div style={{ background: "#FFF0F3", border: `1px solid ${C.red}40`, borderRadius: 10, padding: "9px 14px", marginBottom: 14, fontSize: 13, color: C.red, fontWeight: 700 }}>
                ❌ الكود غلط — حاولي تاني
              </div>
            )}

            <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 10, justifyItems: "center" }}>
              {["1","2","3","4","5","6","7","8","9","","0","⌫"].map((k, i) => {
                if (k === "") return <div key={i} />;
                const isDel = k === "⌫";
                return (
                  <button key={i} className={`numpad-btn${isDel ? " del" : ""}`}
                    onClick={() => { setCodeError(false); isDel ? setCodeInput(p => p.slice(0,-1)) : codeInput.length < 4 && setCodeInput(p => p + k); }}>
                    {k}
                  </button>
                );
              })}
            </div>

            <button onClick={handleLogin} disabled={codeInput.length !== 4}
              style={{ width: "100%", marginTop: 16, height: 54, borderRadius: 14, fontSize: 16, fontWeight: 800, cursor: codeInput.length !== 4 ? "not-allowed" : "pointer", background: codeInput.length === 4 ? `linear-gradient(135deg, ${C.pink}, ${C.mauve})` : C.border, border: "none", color: C.white, boxShadow: codeInput.length === 4 ? `0 6px 20px ${C.shadow}` : "none", transition: "all 0.3s", letterSpacing: 1 }}>
              دخول ✓
            </button>
          </div>
          <p style={{ fontSize: 11, color: C.muted, marginTop: 16, fontWeight: 500 }}>الأكواد التجريبية: 1234 · 5678 · 9012 · 3456</p>
        </div>
      </div>
    );
  }

  const subInfo = getSubInfo(loggedInClient);

  const SubBanner = subInfo ? (
    <div style={{ background: "linear-gradient(135deg, #FDF0F4, #F5EBF8)", border: `1px solid ${C.border}`, borderRadius: 16, padding: "14px 18px", marginBottom: 20, boxShadow: `0 2px 12px ${C.shadow}` }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
        <span style={{ fontSize: 12, color: C.muted, fontWeight: 500 }}>فاضل <strong style={{ color: C.pink }}>{subInfo.remaining}</strong> يوم · <strong style={{ color: C.mauve }}>{subInfo.followupsLeft}</strong> متابعة</span>
        <span style={{ fontSize: 12, color: C.pink, fontWeight: 800 }}>اشتراك {PLAN_LABELS[subInfo.plan]} · أسبوع {subInfo.weeksDone + 1}/{subInfo.weeksTotal}</span>
      </div>
      <div style={{ display: "flex", gap: 4 }}>
        {Array.from({ length: subInfo.weeksTotal }, (_, i) => (
          <div key={i} style={{ flex: 1, height: 6, borderRadius: 99, background: i < subInfo.weeksDone ? C.pink : i === subInfo.weeksDone ? C.lavender : C.blush, transition: "all 0.3s" }} />
        ))}
      </div>
      {subInfo.followupsLeft > 0 && (
        <div style={{ marginTop: 8, fontSize: 12, color: C.mauve, fontWeight: 700 }}>📅 موعد متابعتك القادمة: الأسبوع {subInfo.weeksDone + 1}</div>
      )}
    </div>
  ) : null;

  // ── MILESTONE ──
  const milestoneMsg = subInfo ? WEEK_MESSAGES[Math.min(subInfo.weeksDone - 1, WEEK_MESSAGES.length - 1)] : null;
  if (subInfo?.isWeekMilestone && !dismissedMilestone && milestoneMsg && !submitted && !alreadyLogged) {
    return (
      <div style={S.page}><style>{FONT_STYLE}</style>
        <div style={{ maxWidth: 440, margin: "0 auto" }}>
          {SubBanner}
          <div style={{ background: C.white, border: `1px solid ${C.border}`, borderRadius: 24, padding: "36px 28px", textAlign: "center", boxShadow: `0 8px 32px ${C.shadow}` }}>
            <div style={{ fontSize: 60, marginBottom: 16 }}>🌟</div>
            <h2 style={{ fontSize: 22, fontWeight: 900, color: C.pink, marginBottom: 12 }}>{milestoneMsg.title}</h2>
            <p style={{ fontSize: 15, color: C.sub, lineHeight: 1.9, marginBottom: 24, fontWeight: 500 }}>{milestoneMsg.body}</p>
            {subInfo.followupsLeft > 0 && (
              <div style={{ background: "linear-gradient(135deg,#F5EBF8,#EDE8F5)", border: `1px solid ${C.lavender}`, borderRadius: 14, padding: "14px 18px", marginBottom: 24, textAlign: "right" }}>
                <div style={{ fontSize: 13, color: C.mauve, fontWeight: 800, marginBottom: 4 }}>📅 تذكير بالمتابعة</div>
                <div style={{ fontSize: 13, color: C.sub, fontWeight: 500 }}>فاضل {subInfo.weeksLeft} أسبوع و {subInfo.followupsLeft} متابعة مع دكتورتك</div>
              </div>
            )}
            <button onClick={() => setDismissedMilestone(true)} style={S.submitBtn}>يلا نسجّلي اليوم 🌸</button>
          </div>
        </div>
      </div>
    );
  }

  // ── SUCCESS ──
  if (submitted || alreadyLogged) {
    return (
      <div style={S.page}><style>{FONT_STYLE}</style>
        <div style={{ maxWidth: 440, margin: "0 auto" }}>
          <PageHeader name={loggedInClient.name} onLogout={handleLogout} />
          {SubBanner}
          <div style={{ background: C.white, border: `1px solid ${C.border}`, borderRadius: 24, padding: "36px 28px", textAlign: "center", boxShadow: `0 8px 32px ${C.shadow}` }}>
            <div style={{ fontSize: 60, marginBottom: 16 }}>{alreadyLogged && !submitted ? "📋" : "✅"}</div>
            <h2 style={{ fontSize: 22, fontWeight: 900, color: C.pink, marginBottom: 8 }}>
              {alreadyLogged && !submitted ? "سجّلتِ اليوم!" : "تم الحفظ! 🌸"}
            </h2>
            <p style={{ fontSize: 14, color: C.sub, lineHeight: 1.8, marginBottom: 24, fontWeight: 500 }}>
              {alreadyLogged && !submitted ? `سجلك ليوم ${TODAY} محفوظ.` : "دكتورتك شايفة تحديثك. أحسنتِ!"}
            </p>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginBottom: 20 }}>
              {log.weight && <SChip label="الوزن"    value={`${log.weight} kg`}  color={C.pink} />}
              {log.waist  && <SChip label="الوسط"    value={`${log.waist} cm`}   color={C.mauve} />}
              {log.hips   && <SChip label="الأرداف"  value={`${log.hips} cm`}    color={C.lavender} />}
              {log.arm    && <SChip label="الذراع"   value={`${log.arm} cm`}     color={C.rose} />}
              {log.water  && <SChip label="الماء"    value={`${log.water} L`}    color="#7BACC4" />}
              {log.sleep  && <SChip label="النوم"    value={`${log.sleep} ساعة`} color={C.green} />}
              <SChip label="التوتر" value={`${log.stress}/10`} color={log.stress > 7 ? C.red : C.muted} />
            </div>
            {alreadyLogged && !submitted && (
              <button style={S.outlineBtn} onClick={() => { setAlreadyLogged(false); setStep(0); }}>تعديل تسجيل اليوم</button>
            )}
          </div>
        </div>
      </div>
    );
  }

  // ── MAIN FORM ──
  const steps = [
    { label: "جسم", icon: "⚖️" },
    { label: "أكل", icon: "🌺" },
    { label: "صور", icon: "📸" },
    { label: "عادات", icon: "✨" },
    { label: "مزاج", icon: "💗" },
  ];

  return (
    <div style={S.page}><style>{FONT_STYLE}</style>
      <div style={{ maxWidth: 500, margin: "0 auto" }}>
        <PageHeader name={loggedInClient.name} onLogout={handleLogout} />
        {SubBanner}

        {/* Steps */}
        <div style={{ display: "flex", alignItems: "center", marginBottom: 28, position: "relative" }}>
          <div style={{ position: "absolute", top: 20, left: "8%", right: "8%", height: 2, background: C.borderLight, zIndex: 0 }} />
          {steps.map((s, i) => (
            <div key={i} onClick={() => setStep(i)} style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 5, cursor: "pointer", zIndex: 1, flex: 1 }}>
              <div style={{ width: 40, height: 40, borderRadius: "50%", background: i < step ? C.pink : C.white, border: i === step ? `2.5px solid ${C.pink}` : i < step ? `2px solid ${C.pink}` : `2px solid ${C.border}`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: i < step ? 14 : 16, color: i < step ? C.white : i === step ? C.pink : C.muted, boxShadow: i === step ? `0 4px 14px ${C.shadow}` : "none", transition: "all 0.3s" }}>
                {i < step ? "✓" : s.icon}
              </div>
              <span style={{ fontSize: 10, color: i === step ? C.pink : C.muted, fontWeight: i === step ? 800 : 500 }}>{s.label}</span>
            </div>
          ))}
        </div>

        {/* ── STEP 0 — Body ── */}
        {step === 0 && (
          <div style={S.card}>
            <SectionTitle icon="⚖️" title="القياسات اليومية" />

            <div style={S.grid2}>
              <AField label="الماء (لتر)" type="number" placeholder="مثال: 1.8" value={log.water} onChange={v => set("water", v)} />
              <AField label="النوم (ساعة)" type="number" placeholder="مثال: 7" value={log.sleep} onChange={v => set("sleep", v)} />
            </div>

            {/* Sunday measurements */}
            {IS_SUNDAY ? (
              <>
                <div style={{ background: "linear-gradient(135deg,#FDF0F4,#F8EBF5)", border: `1px solid ${C.border}`, borderRadius: 14, padding: "12px 16px", marginBottom: 16, display: "flex", alignItems: "center", gap: 10 }}>
                  <span style={{ fontSize: 22 }}>📏</span>
                  <div>
                    <div style={{ fontSize: 14, color: C.pink, fontWeight: 800 }}>قياسات الأسبوع</div>
                    <div style={{ fontSize: 12, color: C.muted, fontWeight: 500 }}>كل أحد بنسجل الوزن والمقاسات 🌸</div>
                  </div>
                </div>
                <div style={S.grid2}>
                  <AField label="الوزن (كجم)" type="number" placeholder="مثال: 71.4" value={log.weight} onChange={v => set("weight", v)} />
                  <AField label="مقاس الوسط (سم)" type="number" placeholder="مثال: 72" value={log.waist} onChange={v => set("waist", v)} />
                </div>
                <div style={S.grid2}>
                  <AField label="مقاس الأرداف (سم)" type="number" placeholder="مثال: 98" value={log.hips} onChange={v => set("hips", v)} />
                  <AField label="مقاس الذراع (سم)" type="number" placeholder="مثال: 30" value={log.arm} onChange={v => set("arm", v)} />
                </div>
                {/* Period — Sunday only */}
                <AYesNo label="الدورة الشهرية 🩸" value={log.period} onChange={v => set("period", v)} yesColor={C.rose} />
              </>
            ) : (
              <div style={{ background: C.peach, border: `1px solid #F0D8CC`, borderRadius: 12, padding: "12px 16px", marginBottom: 16, textAlign: "center" }}>
                <div style={{ fontSize: 13, color: C.muted, fontWeight: 600 }}>📏 القياسات الأسبوعية بتيجي يوم الأحد بس</div>
              </div>
            )}

            {/* Stress slider */}
            <div style={{ display: "flex", flexDirection: "column", gap: 8, marginTop: 4 }}>
              <label style={S.lbl}>مستوى التوتر <strong style={{ color: C.red }}>{log.stress}/10</strong></label>
              <input type="range" min="1" max="10" value={log.stress} onChange={e => set("stress", +e.target.value)} style={{ accentColor: C.red, cursor: "pointer", width: "100%" }} />
              <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11, color: C.muted, fontWeight: 500 }}><span>منخفض ١</span><span>١٠ عالي</span></div>
            </div>
          </div>
        )}

        {/* ── STEP 1 — Food ── */}
        {step === 1 && (
          <div style={S.card}>
            <SectionTitle icon="🌺" title="الغذاء والتغذية" />
            <div style={S.grid2}>
              <AField label="عدد الوجبات" type="number" placeholder="مثال: 3" value={log.meals} onChange={v => set("meals", v)} />
              <AField label="القهوة (كوب)" type="number" placeholder="مثال: 2" value={log.coffee} onChange={v => set("coffee", v)} />
            </div>
            <div style={S.grid2}>
              <AYesNo label="السلطة 🥗" value={log.salad} onChange={v => set("salad", v)} yesColor={C.green} />
              <AYesNo label="وجبة سريعة 🍔" value={log.fastFood} onChange={v => set("fastFood", v)} yesColor={C.red} />
            </div>
          </div>
        )}

        {/* ── STEP 2 — Photos ── */}
        {step === 2 && (
          <div style={S.card}>
            <SectionTitle icon="📸" title="صور الوجبات" sub={photoCount > 0 ? `${photoCount} من 4 تم الإضافة ✓` : "اختياري — اضغطي لرفع صورة"} />
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
              {MEALS.map(meal => (
                <MealPhotoCard key={meal.key} meal={meal} photo={log.photos?.[meal.key]} onPhoto={d => setPhoto(meal.key, d)} onClear={() => setPhoto(meal.key, null)} />
              ))}
            </div>
          </div>
        )}

        {/* ── STEP 3 — Habits ── */}
        {step === 3 && (
          <div style={S.card}>
            <SectionTitle icon="✨" title="العادات اليومية" />
            <div style={S.grid2}>
              <AYesNo label="الالتزام بالخطة ✅" value={log.followedPlan} onChange={v => set("followedPlan", v)} yesColor={C.pink} />
              <AYesNo label="المكملات الغذائية 💊" value={log.supplements} onChange={v => set("supplements", v)} yesColor={C.mauve} />
            </div>
            <div style={S.grid2}>
              <AYesNo label="التمرين 🏃" value={log.exercise} onChange={v => set("exercise", v)} yesColor={C.pink} />
              {log.exercise && <AField label="مدة التمرين (دقيقة)" type="number" placeholder="مثال: 30" value={log.exerciseMin} onChange={v => set("exerciseMin", v)} />}
            </div>
            <AYesNo label="أكل عاطفي / شراهة ⚠️" value={log.binge} onChange={v => set("binge", v)} yesColor={C.red} />
          </div>
        )}

        {/* ── STEP 4 — Mood ── */}
        {step === 4 && (
          <div style={S.card}>
            <SectionTitle icon="💗" title="المزاج والملاحظات" />
            <div style={{ display: "flex", gap: 8, justifyContent: "center", marginBottom: 24 }}>
              {["😞","😐","🙂","😊","🌟"].map(m => (
                <button key={m} onClick={() => set("mood", m)} style={{ width: 56, height: 56, borderRadius: 14, cursor: "pointer", fontSize: 26, background: log.mood === m ? C.blush : C.white, border: log.mood === m ? `2.5px solid ${C.pink}` : `1.5px solid ${C.border}`, boxShadow: log.mood === m ? `0 4px 12px ${C.shadow}` : "none", transition: "all 0.2s", display: "flex", alignItems: "center", justifyContent: "center" }}>{m}</button>
              ))}
            </div>
            <label style={S.lbl}>ملاحظات لدكتورتك</label>
            <textarea style={S.textarea} placeholder="كيف حالك؟ أي أعراض أو انجازات اليوم..." value={log.note} onChange={e => set("note", e.target.value)} rows={4} />
          </div>
        )}

        {/* Nav */}
        <div style={{ display: "flex", alignItems: "center", gap: 12, marginTop: 8 }}>
          {step > 0 && <button style={S.outlineBtn} onClick={() => setStep(s => s - 1)}>← السابق</button>}
          <div style={{ flex: 1 }} />
          {step < 4
            ? <button style={S.nextBtn} onClick={() => setStep(s => s + 1)}>التالي ←</button>
            : <button style={S.submitBtn} onClick={handleSubmit} disabled={loading}>{loading ? "جاري الحفظ..." : "✓ إرسال التسجيل"}</button>
          }
        </div>
      </div>
    </div>
  );
}

// ── COMPONENTS ──

function PageHeader({ name, onLogout }) {
  const firstName = name.split(" ")[0];
  return (
    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
      <div>
        <h1 style={{ fontSize: 24, fontWeight: 900, color: C.text, margin: 0 }}>أهلاً، {firstName} 🌸</h1>
        <p style={{ fontSize: 13, color: C.muted, marginTop: 3, fontWeight: 500 }}>
          {new Date().toLocaleDateString("ar-EG", { weekday: "long", day: "numeric", month: "long" })}
        </p>
      </div>
      <button onClick={onLogout} style={{ background: C.peach, border: `1px solid #F0D8CC`, borderRadius: 10, color: C.sub, padding: "8px 16px", fontSize: 13, fontWeight: 700, cursor: "pointer" }}>
        خروج ↩
      </button>
    </div>
  );
}

function SectionTitle({ icon, title, sub }) {
  return (
    <div style={{ marginBottom: 20 }}>
      <h3 style={{ fontSize: 19, fontWeight: 900, color: C.text, margin: 0 }}>{icon} {title}</h3>
      {sub && <p style={{ fontSize: 12, color: C.muted, margin: "4px 0 0", fontWeight: 500 }}>{sub}</p>}
    </div>
  );
}

function AField({ label, type, placeholder, value, onChange }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 7 }}>
      <label style={S.lbl}>{label}</label>
      <input type={type || "text"} placeholder={placeholder} value={value} onChange={e => onChange(e.target.value)} style={S.input} />
    </div>
  );
}

function AYesNo({ label, value, onChange, yesColor }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 7, marginBottom: 14 }}>
      <label style={S.lbl}>{label}</label>
      <div style={{ display: "flex", gap: 10 }}>
        {[true, false].map(v => (
          <button key={String(v)} onClick={() => onChange(v)} style={{
            flex: 1, padding: "12px 0", borderRadius: 12,
            fontSize: 16, fontWeight: 800, cursor: "pointer",
            background: value === v ? (v ? `${yesColor}18` : "#FFF0F3") : C.white,
            border: value === v ? `2px solid ${v ? yesColor : C.red}` : `1.5px solid ${C.border}`,
            color: value === v ? (v ? yesColor : C.red) : C.muted,
            boxShadow: value === v ? `0 2px 10px ${value === v && v ? yesColor : C.red}25` : "none",
            transition: "all 0.2s",
          }}>
            {v ? "نعم" : "لا"}
          </button>
        ))}
      </div>
    </div>
  );
}

function SChip({ label, value, color }) {
  return (
    <div style={{ background: C.bg, border: `1px solid ${C.border}`, borderRadius: 12, padding: "12px 14px", textAlign: "center" }}>
      <div style={{ fontSize: 10, color: C.muted, letterSpacing: 0.5, marginBottom: 4, fontWeight: 600 }}>{label}</div>
      <div style={{ fontSize: 16, fontWeight: 800, color }}>{value}</div>
    </div>
  );
}

function MealPhotoCard({ meal, photo, onPhoto, onClear }) {
  function handleFile(e) {
    const file = e.target.files[0]; if (!file) return;
    const reader = new FileReader();
    reader.onload = ev => onPhoto(ev.target.result);
    reader.readAsDataURL(file);
  }
  return (
    <div style={{ background: photo ? "#000" : C.bg, border: `2px dashed ${photo ? meal.color : C.border}`, borderRadius: 18, overflow: "hidden", position: "relative", aspectRatio: "1", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center" }}>
      {photo ? (
        <>
          <img src={photo} alt={meal.label} style={{ width: "100%", height: "100%", objectFit: "cover", position: "absolute", top: 0, left: 0 }} />
          <div style={{ position: "absolute", inset: 0, background: "linear-gradient(to top, rgba(0,0,0,0.7) 0%, transparent 50%)" }} />
          <div style={{ position: "absolute", bottom: 10, left: 0, right: 0, textAlign: "center" }}>
            <div style={{ fontSize: 13, color: "#fff", fontWeight: 800 }}>{meal.label}</div>
          </div>
          <button onClick={onClear} style={{ position: "absolute", top: 8, right: 8, background: "rgba(0,0,0,0.6)", border: "none", borderRadius: "50%", width: 28, height: 28, color: "#fff", fontSize: 14, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center" }}>✕</button>
        </>
      ) : (
        <label style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 8, cursor: "pointer", padding: 14, width: "100%", height: "100%", justifyContent: "center" }}>
          <input type="file" accept="image/*" capture="environment" style={{ display: "none" }} onChange={handleFile} />
          <div style={{ width: 64, height: 64, borderRadius: "50%", background: `${meal.color}15`, border: `2px solid ${meal.color}50`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 30, boxShadow: `0 4px 16px ${meal.color}25` }}>{meal.icon}</div>
          <div style={{ fontSize: 14, color: meal.color, fontWeight: 800 }}>{meal.label}</div>
          <div style={{ fontSize: 11, color: C.muted, background: C.white, padding: "4px 12px", borderRadius: 99, border: `1px solid ${C.border}`, fontWeight: 600 }}>📷 إضافة صورة</div>
        </label>
      )}
    </div>
  );
}

const S = {
  page: { background: C.bg, minHeight: "100vh", padding: "28px 20px", color: C.text },
  card: { background: C.white, border: `1px solid ${C.border}`, borderRadius: 20, padding: "24px 22px", marginBottom: 18, boxShadow: `0 4px 20px ${C.shadow}` },
  grid2: { display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14, marginBottom: 16 },
  lbl: { fontSize: 13, color: C.sub, fontWeight: 700 },
  input: { background: C.bg, border: `1.5px solid ${C.border}`, borderRadius: 10, padding: "12px 14px", color: C.text, fontSize: 15, fontWeight: 600, outline: "none", width: "100%", boxSizing: "border-box" },
  textarea: { background: C.bg, border: `1.5px solid ${C.border}`, borderRadius: 12, padding: "12px 14px", color: C.text, fontSize: 14, fontWeight: 500, outline: "none", width: "100%", resize: "vertical", marginTop: 8 },
  outlineBtn: { background: C.white, border: `1.5px solid ${C.border}`, borderRadius: 12, color: C.sub, padding: "12px 24px", fontSize: 14, fontWeight: 700, cursor: "pointer" },
  nextBtn: { background: C.white, border: `2px solid ${C.pink}`, borderRadius: 12, color: C.pink, padding: "12px 28px", fontSize: 15, fontWeight: 800, cursor: "pointer", boxShadow: `0 4px 12px ${C.shadow}` },
  submitBtn: { background: `linear-gradient(135deg, ${C.pink}, ${C.mauve})`, border: "none", borderRadius: 14, color: C.white, padding: "14px 36px", fontSize: 16, fontWeight: 800, cursor: "pointer", boxShadow: `0 6px 20px ${C.shadow}` },
};
